query GetNotification($notificationId: ID!) {
  notifications {
    notification(notificationId: $notificationId) {
      id
      type
      priority
      title
      message
      read
      createdAt
    }
  }
}

query GetUnreadCount {
  notifications {
    unreadCount {
      count
    }
  }
}

{
