# 1. Get unread count
query GetUnreadCount {
  notifications {
    unreadCount {
      count
    }
  }
}

# 2. List unread notifications
query ListUnread {
  notifications {
    notifications(filters: {
      unreadOnly: true
      limit: 20
    }) {
      items {
        id
        type
        priority
        title
        message
        createdAt
      }
      pageInfo {
        total
      }
    }
  }
}

# 3. Mark notification as read
mutation MarkAsRead {
  notifications {
    markNotificationAsRead(notificationId: "1") {
      id
      read
      readAt
    }
  }
}

# 4. Mark multiple as read
mutation MarkMultiple {
  notifications {
    markNotificationsAsRead(input: {
      notificationIds: ["1", "2", "3"]
    }) {
      count
    }
  }
}

# 5. Delete notifications
mutation Delete {
  notifications {
    deleteNotifications(input: {
      notificationIds: ["1", "2"]
    }) {
      count
    }
  }
}

# 6. Update preferences
mutation UpdatePrefs {
  notifications {
    updateNotificationPreferences(input: {
      emailDigest: true
      newLeads: true
      marketing: false
    }) {
      emailDigest
      newLeads
      marketing
    }
  }
}
